**Services/CatalogService.cs** — an in-memory data service with seed data:
```csharp
namespace UniversityCourseCatalog.Services;

using UniversityCourseCatalog.Models;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "The abstract science of number, quantity, and space." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Literature, writing, and language studies." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and human civilization." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Fundamentals of programming using C#. Covers variables, control flow, functions, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of teaching experience and specializes in programming pedagogy and software engineering.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, Title = "Data Structures and Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research focuses on algorithm optimization and computational complexity theory.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, Title = "Database Systems", Code = "CS 340", Description = "Relational database design, SQL, normalization, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked in industry for 10 years building large-scale distributed database systems before joining academia.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 2, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Williams", InstructorBio = "Dr. Williams is an award-winning educator who has published extensively on mathematical analysis.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, Title = "Linear Algebra", Code = "MATH 220", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Zhao", InstructorBio = "Dr. Zhao specializes in applied linear algebra and numerical methods.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 3, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM + Fri Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster's research is in experimental condensed matter physics.", IsFeatured = true },
            new() { Id = 7, DepartmentId = 3, Title = "Quantum Mechanics", Code = "PHYS 301", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, and quantum operators.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Priya Nair", InstructorBio = "Dr. Nair is a theoretical physicist whose work spans quantum information and particle physics.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 4, Title = "English Composition", Code = "ENG 101", Description = "Develop college-level writing skills through essays, research papers, and peer review.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published author and has taught composition courses for over 20 years.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 4, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Angela Morris", InstructorBio = "Dr. Morris specializes in 20th-century American fiction and has won multiple literary criticism awards.", IsFeatured = false },
            new() { Id = 10, DepartmentId = 5, Title = "World History", Code = "HIST 101", Description = "A broad survey of world civilizations from ancient times to the modern era.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is a historian specializing in comparative civilizations and global trade networks.", IsFeatured = true }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}
```

