### 4. Pages

**Delete** `Components/Pages/Counter.razor` and `Components/Pages/Weather.razor` (the template defaults).

**Components/Pages/Home.razor:**
```razor
@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the university course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &bull; @course.InstructorName</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="list-group">
    @foreach (var dept in departments)
    {
        <a href="departments/@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Code</strong> &mdash; @dept.Name
        </a>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetAllDepartments();
    }
}
```

**Components/Pages/Courses.razor:**
```razor
@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="courses">
    <div class="row mb-3">
        <div class="col-md-6">
            <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
        </div>
        <div class="col-md-4">
            <select name="departmentId" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetAllDepartments();
        courses = Catalog.SearchCourses(Search, DepartmentId);
    }
}
```

