            new() { Id = 4, DepartmentId = 2, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Williams", InstructorBio = "Dr. Williams is an award-winning educator who has published extensively on mathematical analysis.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, Title = "Linear Algebra", Code = "MATH 220", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Zhao", InstructorBio = "Dr. Zhao specializes in applied linear algebra and numerical methods.", IsFeatured = false },
