            new() { Id = 7, DepartmentId = 3, Title = "Quantum Mechanics", Code = "PHYS 301", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, and quantum operators.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Priya Nair", InstructorBio = "Dr. Nair is a theoretical physicist whose work spans quantum information and particle physics.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 4, Title = "English Composition", Code = "ENG 101", Description = "Develop college-level writing skills through essays, research papers, and peer review.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published author and has taught composition courses for over 20 years.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 4, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Angela Morris", InstructorBio = "Dr. Morris specializes in 20th-century American fiction and has won multiple literary criticism awards.", IsFeatured = false },
            new() { Id = 10, DepartmentId = 5, Title = "World History", Code = "HIST 101", Description = "A broad survey of world civilizations from ancient times to the modern era.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is a historian specializing in comparative civilizations and global trade networks.", IsFeatured = true }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}
