**Components/Pages/Enroll.razor:**
```razor
@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. All fields are required.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your request to enroll in <strong>@selectedCourseTitle</strong> has been received. You will receive a confirmation via your student email.</p>
        <a href="enroll" class="btn btn-primary">Submit Another Request</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in allCourses)
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> allCourses = new();
    private bool submitted;
    private string selectedCourseTitle = "";

    protected override void OnInitialized()
    {
        allCourses = Catalog.GetAllCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(Model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.Code} - {course.Title}" : "Unknown Course";
        submitted = true;
    }
}
```

